import socket
import json

# Game state simulation
game_state = {
    "players": [
        {"id": 1, "name": "Player1", "score": 10},
        {"id": 2, "name": "Player2", "score": 5}
    ],
    "status": "running"
}

# Create a UDP socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
server_address = ('', 12345)  # Listen on all interfaces at port 12345

# Bind the socket to the address and port
server_socket.bind(server_address)

print("Game server is listening for UDP queries...")

while True:
    data, client_address = server_socket.recvfrom(4096)
    
    if not data:
        break
    
    query = data.decode('utf-8')
    
    if query == "STATUS":
        response = json.dumps(game_state)
        
        # Send the large response to the client
        server_socket.sendto(response.encode('utf-8'), client_address)